func HasArticle() predicate.ArticleVersion {
	return predicate.ArticleVersion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ArticleTable, ArticleColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasArticleWith applies the HasEdge predicate on the "article" edge with a given conditions (other predicates).
func HasArticleWith(preds ...predicate.Article) predicate.ArticleVersion {
	return predicate.ArticleVersion(func(s *sql.Selector) {
		step := newArticleStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasEditor applies the HasEdge predicate on the "editor" edge.
func HasEditor() predicate.ArticleVersion {
	return predicate.ArticleVersion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, EditorTable, EditorColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEditorWith applies the HasEdge predicate on the "editor" edge with a given conditions (other predicates).
func HasEditorWith(preds ...predicate.User) predicate.ArticleVersion {
	return predicate.ArticleVersion(func(s *sql.Selector) {
		step := newEditorStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ArticleVersion) predicate.ArticleVersion {
	return predicate.ArticleVersion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ArticleVersion) predicate.ArticleVersion {
	return predicate.ArticleVersion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ArticleVersion) predicate.ArticleVersion {
	return predicate.ArticleVersion(sql.NotPredicates(p))
}
